prompt --application/pages/page_00004
begin
wwv_flow_imp_page.create_page(
 p_id=>4
,p_name=>'Detalle Bar'
,p_alias=>'DETALLE-BAR'
,p_step_title=>'Detalle Bar'
,p_autocomplete_on_off=>'OFF'
,p_javascript_code_onload=>wwv_flow_string.join(wwv_flow_t_varchar2(
'const API_BASE = ''https://parranderos-api-fc5w.onrender.com/bares'';',
'const barId = parseInt(apex.item(''P_BAR_ID'').getValue());',
'',
'function cargarComentarios() {',
'    fetch(`${API_BASE}/${barId}/comentarios`)',
'        .then(res => res.json())',
'        .then(data => {',
'            const container = document.getElementById(''comentarios-container'');',
'            if (data.length === 0) {',
unistr('                container.innerHTML = ''<p>No hay comentarios a\00FAn. \00A1S\00E9 el primero!</p>'';'),
'                return;',
'            }',
'            container.innerHTML = data.map(c => `',
'                <div style="border:1px solid #ddd; border-radius:8px; padding:12px; margin-bottom:10px;">',
unistr('                    <strong>${c.autor || c.nombre || ''An\00F3nimo''}</strong>'),
'                    <span style="color:#888; font-size:0.85em; margin-left:10px;">',
'                        ${c.fecha ? new Date(c.fecha).toLocaleDateString(''es-CO'') : ''''}',
'                    </span>',
'                    <p style="margin-top:6px;">${c.texto || c.comentario || ''''}</p>',
'                </div>',
'            `).join('''');',
'        })',
'        .catch(err => {',
'            document.getElementById(''comentarios-container'').innerHTML =',
'                ''<p style="color:red;">Error cargando comentarios.</p>'';',
'        });',
'}',
'',
'function enviarComentario() {',
'    const texto = apex.item(''P_TEXTO_COMENTARIO'').getValue();',
'    if (!texto.trim()) {',
unistr('        apex.message.showErrors([{ message: ''El comentario no puede estar vac\00EDo.'' }]);'),
'        return;',
'    }',
'    fetch(`${API_BASE}/${barId}/comentarios`, {',
'        method: ''POST'',',
'        headers: { ''Content-Type'': ''application/json'' },',
'        body: JSON.stringify({',
'            bar_id: parseInt(barId),',
'            texto: texto,',
'            autor: apex.env.APP_USER',
'        })',
'    })',
'    .then(res => res.json())',
'    .then(() => {',
'        apex.item(''P_TEXTO_COMENTARIO'').setValue('''');',
'        cargarComentarios();',
'    })',
'    .catch(() => {',
'        apex.message.showErrors([{ message: ''Error enviando el comentario.'' }]);',
'    });',
'}',
'',
'cargarComentarios();',
'',
'function cargarEventos() {',
'    fetch(`${API_BASE}/${barId}/eventos`)',
'        .then(res => res.json())',
'        .then(data => {',
'            const container = document.getElementById(''eventos-container'');',
'            if (data.length === 0) {',
unistr('                container.innerHTML = ''<p>No hay eventos a\00FAn.</p>'';'),
'                return;',
'            }',
'            container.innerHTML = data.map(e => `',
'                <div style="border:1px solid #ddd; border-radius:8px; padding:12px; margin-bottom:10px;">',
'                    <strong>${e.nombre || e.evento || ''Sin nombre''}</strong>',
'                    <span style="color:#888; font-size:0.85em; margin-left:10px;">',
'                        ${e.fecha_creacion ? new Date(e.fecha_creacion).toLocaleDateString(''es-CO'') : ''''}',
'                    </span>',
unistr('                    ${e.dia ? `<p> D\00EDa: ${e.dia}</p>` : ''''}'),
'                    ${e.banda ? `<p> Banda: ${e.banda}</p>` : ''''}',
'                    ${e.artista ? `<p> Artista: ${e.artista}</p>` : ''''}',
'                    ${e.cover ? `<p> Cover: $${e.cover}</p>` : ''''}',
'                    ${e.descuento ? `<p> Descuento: ${e.descuento}</p>` : ''''}',
'                    ${e.hora_inicio ? `<p> Hora: ${e.hora_inicio} - ${e.hora_fin || ''''}</p>` : ''''}',
'                    ${e.cupos ? `<p> Cupos: ${e.cupos}</p>` : ''''}',
'                </div>',
'            `).join('''');',
'        })',
'        .catch(() => {',
'            document.getElementById(''eventos-container'').innerHTML =',
'                ''<p style="color:red;">Error cargando eventos.</p>'';',
'        });',
'}',
'',
'cargarEventos();'))
,p_page_template_options=>'#DEFAULT#'
,p_protection_level=>'C'
,p_page_component_map=>'03'
,p_last_updated_by=>'CO_B331_SQL_S27_ADMIN'
,p_last_upd_yyyymmddhh24miss=>'20260517003130'
);
