,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'const API_BASE = ''https://parranderos-api-fc5w.onrender.com/bares'';',
'const barId = parseInt(apex.item(''P_BAR_ID'').getValue());',
'const nombre = apex.item(''P_EVENTO_NOMBRE'').getValue();',
'',
'if (!nombre.trim()) {',
'    apex.message.showErrors([{ message: ''El nombre del evento es obligatorio.'' }]);',
'    return;',
'}',
'',
'// Construir el documento solo con campos completados',
'const evento = { nombre: nombre };',
'',
'const artista = apex.item(''P_EVENTO_ARTISTA'').getValue();',
'const cover = apex.item(''P_EVENTO_COVER'').getValue();',
'const descuento = apex.item(''P_EVENTO_DESCUENTO'').getValue();',
'const dia = apex.item(''P_EVENTO_DIA'').getValue();',
'const banda = apex.item(''P_EVENTO_BANDA'').getValue();',
'const cupos = apex.item(''P_EVENTO_CUPOS'').getValue();',
'',
'if (artista.trim()) evento.artista = artista;',
'if (cover.trim()) evento.cover = cover;',
'if (descuento.trim()) evento.descuento = descuento;',
'if (dia.trim()) evento.dia = dia;',
'if (banda.trim()) evento.banda = banda;',
'if (cupos.trim()) evento.cupos = cupos;',
'',
'fetch(`${API_BASE}/${barId}/eventos`, {',
'    method: ''POST'',',
'    headers: { ''Content-Type'': ''application/json'' },',
'    body: JSON.stringify(evento)',
'})',
'.then(res => res.json())',
'.then(() => {',
'    apex.item(''P_EVENTO_NOMBRE'').setValue('''');',
'    apex.item(''P_EVENTO_ARTISTA'').setValue('''');',
'    apex.item(''P_EVENTO_COVER'').setValue('''');',
'    apex.item(''P_EVENTO_DESCUENTO'').setValue('''');',
'    apex.item(''P_EVENTO_DIA'').setValue('''');',
'    apex.item(''P_EVENTO_BANDA'').setValue('''');',
'    apex.item(''P_EVENTO_CUPOS'').setValue('''');',
'    location.reload();',
'})',
'.catch(() => {',
'    apex.message.showErrors([{ message: ''Error guardando el evento.'' }]);',
'});'))
);
end;
